INSERT INTO `character` VALUES (1,'李渊','男',566,635,'长安（今陕西省西安市）','出身关陇贵族世家，西魏八柱国之一李虎之孙，七岁袭封唐国公，早年仕隋，深得隋文帝与独孤皇后信任，隋末天下大乱时于太原起兵反隋，攻占长安后接受隋恭帝禅位，建立唐朝，是唐朝开国皇帝，玄武门之变后退位为太上皇','宽厚豁达，沉稳有谋，善于笼络人心','唐朝',1,'2026-04-01 13:13:19.429351','2026-04-08 11:01:47.206787','/images/li_yuan.webp'),(2,'李世民','男',598,649,'岐州武功县（今陕西省咸阳市武功县）','唐高祖李渊与太穆皇后窦氏次子，唐朝第二位皇帝。年少时就展现出出色的军事才能，隋末劝说李渊晋阳起兵反隋，唐朝建立后受封秦王，率军平定薛仁杲、刘武周、窦建德、王世充等割据势力，为全国统一立下赫赫战功。武德九年发动玄武门之变被册立为太子，不久后即位，在位期间开创了著名的治世“贞观之治”，为后来唐朝的全盛奠定了重要基础。','英明果断、雄才大略，知人善任、从谏如流，胸怀开阔，兼具极高的军事谋略与政治治理能力','唐朝',1,'2026-04-01 13:34:21.780567','2026-04-08 11:24:29.000000','/images/1775618669739-li_shimin.webp'),(20,'刘文静','男',568,619,'京兆武功（今陕西省咸阳市武功县）','出身京兆刘氏，隋末任晋阳令，与李世民、裴寂共同谋划晋阳起兵，是唐朝开国核心元勋之一，唐朝建立后任纳言、民部尚书，封鲁国公，曾主持修订唐代律令基础，后因与同僚裴寂失和遭诬陷谋反，被唐高祖李渊处死，贞观年间获平反','足智多谋，胸怀大志，但性情傲岸，恃才负气，不甘居人之下','唐朝',1,'2026-04-08 10:21:55.465862','2026-04-08 11:31:12.000000','/images/1775619072773-liu_wenjing.webp'),(21,'杨坚','男',541,604,'冯翊般若寺（今陕西省渭南市大荔县）','北周随国公杨忠之子，北周外戚，长女杨丽华是北周宣帝宇文赟的皇后，后接受北周静帝宇文阐禅位登基，建立隋朝，攻灭南陈完成全国统一，结束了南北朝长期分裂的局面，在位期间开创“开皇之治”','沉稳有谋略，早期节俭勤政、励精图治，晚年多疑苛察、用法严苛','隋朝',1,'2026-04-08 10:32:58.862508','2026-04-08 12:28:07.000000','/images/1775622487506-yang_jian.webp'),(22,'杨广','男',569,618,'冯翊般若寺（今陕西省渭南市大荔县）','隋文帝杨坚与文献皇后独孤伽罗次子，初封晋王，后通过夺嫡取代兄长杨勇成为皇太子，公元604年即位为隋朝第二位皇帝，在位期间推行营建东都、开凿大运河、西征吐谷浑、改官制、开科举等举措，也因频繁发动战争、滥用民力引发隋末农民起义，最终在江都兵变中被杀。','兼具雄才大略与骄奢残暴的特质，好大喜功、刚愎自用，不恤民力，行事偏执极端。','隋朝',1,'2026-04-08 12:06:01.566695','2026-04-08 12:35:56.000000','/images/1775622956028-yang_guang.webp'),(24,'高颎','男',541,607,'渤海蓨县（今河北省景县）','出身官宦世家，父亲高宾曾仕北齐后投奔北周，被赐姓独孤氏。高颎早年出仕北周，后被隋文帝杨坚倚重，是隋朝开国元勋，主导隋初制度修订、新都营建、平陈统一等核心事务，为“开皇之治”立下卓著功勋，后因反对废黜太子杨勇遭疏远，隋炀帝即位后因议论朝政被诛杀。','聪慧明察，有雄才大略，为人刚直敢言，为政勤勉清廉，举荐贤能不居功自傲。','隋朝',1,'2026-04-08 12:31:26.855167','2026-04-08 12:51:26.000000','/images/1775623886684-gao_jiong_v2.webp'),(25,'杨素','男',544,606,'弘农华阴（今陕西省华阴市）','出身弘农杨氏世族，早年出仕北周，后追随隋文帝杨坚，为隋朝开国元勋，曾参与灭陈、平定江南叛乱、北击突厥等重大军事行动，因功封越国公，后协助晋王杨广夺取储位，隋炀帝即位后官至司徒，改封楚国公，是隋朝权倾一时的重臣','足智多谋，治军严整，才思敏捷，但同时恃权骄纵，擅弄权术，心胸狭隘，为巩固权位曾排除异己','隋朝',1,'2026-04-08 12:54:28.174847','2026-04-08 12:58:56.000000','/images/1775624336490-yang_su.webp'),(26,'宇文化及','男',577,619,'代郡武川（今内蒙古自治区武川县）','北周上柱国宇文盛之孙，隋朝左卫大将军宇文述长子，早年为隋炀帝杨广近臣，深得宠信，隋末大乱时发动江都政变弑杀杨广，先自立为大丞相，后建国号许，年号天寿','骄横贪婪，怯懦无谋，贪图享乐','隋朝',1,'2026-04-08 13:06:50.041320','2026-04-08 13:10:00.000000','/images/1775625000987-yuwen_huaji.webp'),(27,'房玄龄','男',579,648,'齐州临淄（今山东省淄博市临淄区）','出身官宦士族家庭，初仕隋朝任隰城县尉，后投奔秦王李世民，成为其核心谋臣，是玄武门之变的主要策划者之一，位列凌烟阁二十四功臣，唐太宗时期官至尚书左仆射、封梁国公，与杜如晦并称“房谋杜断”，主持修订典章律令、监修国史，是贞观之治的重要缔造者之一','足智多谋、处事缜密，勤勉恭谨，为人宽厚谦让，不居功自傲','唐朝',1,'2026-04-08 13:11:55.008551','2026-04-08 13:14:04.000000','/images/1775625244926-fang_xuanling.webp'),(28,'杜如晦','男',585,630,'京兆郡杜陵县（今陕西省西安市长安区）','出身关中名门京兆杜氏，早年曾在隋朝任滏阳县尉，后成为秦王李世民的核心谋臣，辅佐李世民平定多方割据势力、策划玄武门之变，唐太宗即位后官至尚书右仆射，封蔡国公，与房玄龄共同执掌朝政、开创贞观之治，二人并称“房谋杜断”，位列凌烟阁二十四功臣','聪慧缜密，处事果决，为人谦逊持重，理政务实公允','唐朝',1,'2026-04-08 13:18:21.199002','2026-04-08 13:22:43.000000','/images/1775625763938-du_ruhui.webp'),(29,'李靖','男',571,649,'雍州三原（今陕西省咸阳市三原县）','出身官宦世家，为隋朝凉州刺史李诠之子，早年在隋朝为官，后归附李唐政权，是初唐杰出军事家，位列凌烟阁二十四功臣之一。一生南征北战，先后平定萧铣、辅公祏割据势力，率军攻灭东突厥、大破吐谷浑，为唐朝的统一和边境安定立下不世之功，官至兵部尚书，封卫国公，世称李卫公','沉稳果决，多谋善断，治军严明，为人谦逊谨慎，不慕权位','唐朝',1,'2026-04-08 13:23:24.266751','2026-04-08 13:25:37.000000','/images/1775625937157-li_jing.webp'),(30,'李勣','男',594,669,'曹州离狐（今山东省菏泽市东明县）','原名徐世勣，字懋功，早年投身瓦岗军，后归降唐朝被赐李姓，为避唐太宗李世民名讳改名李勣，位列凌烟阁二十四功臣，历仕唐高祖、唐太宗、唐高宗三朝，曾参与平定王世充、窦建德等割据势力，率军击灭东突厥、高句丽，是唐初杰出军事统帅，出将入相，官至司空、太子太师，封英国公。','忠义持重，多谋善断，体恤士卒，知人善任，重诺守信','唐朝',1,'2026-04-08 13:26:44.202231','2026-04-08 13:31:48.000000','/images/1775626308805-li_ji.webp'),(31,'秦琼','男','?',638,'齐州历城（今山东省济南市）','隋末唐初名将，初为隋将，先后在来护儿、张须陀、裴仁基帐下任职，后随裴仁基投奔瓦岗军领袖李密，瓦岗败亡后转投王世充，因不满王世充为人奸诈，与程咬金等人一同投奔李唐，跟随秦王李世民南征北战，立下赫赫战功，位列凌烟阁二十四功臣之一','忠勇仗义、勇武过人、重情重义、行事正直','唐朝',1,'2026-04-08 14:37:25.168539','2026-04-08 14:37:25.168539','/images/ancient_character_men.webp'),(32,'尉迟恭','男',585,658,'朔州善阳（今山西省朔州市）','隋末唐初开国名将，凌烟阁二十四功臣之一，早年曾效力于刘武周势力，归唐后追随李世民南征北战，在玄武门之变中立下汗马功劳，官至右武候大将军，封鄂国公，后世与秦琼一同被奉为传统门神','勇武善战、忠厚憨直、刚正不阿','唐朝',1,'2026-04-08 14:40:53.343274','2026-04-08 14:40:53.343274','/images/ancient_character_men.webp'),(33,'程咬金','男',589,665,'济州东阿（今山东省东平县）','隋末唐初开国名将，凌烟阁二十四功臣之一，早年投身瓦岗军，后归降唐朝，追随秦王李世民平定王世充、窦建德等割据势力，参与玄武门之变，因功封卢国公，为唐朝开国元勋','骁勇善战，豪爽仗义，忠直果敢，粗中有细','唐朝',1,'2026-04-08 14:56:45.929293','2026-04-08 14:56:45.929293','/images/ancient_character_men.webp'),(34,'薛仁贵','男',614,683,'绛州龙门县（今山西省河津市）','出身河东薛氏南祖房，为北魏河东王薛安都六世孙，早年家道中落以农耕为业，唐太宗时期应征入伍，征战数十年立下赫赫战功，是唐朝初年著名军事将领，留下了“三箭定天山”“降服高句丽”等诸多经典典故','忠勇果敢，智勇兼备，治军严明，心怀家国','唐朝',1,'2026-04-08 15:00:14.468696','2026-04-08 15:00:14.468696','/images/ancient_character_men.webp'),(35,'郭子仪','男',697,781,'华州郑县（今陕西省渭南市华州区）','出身官宦世家，早年以武举高第入仕从军，安史之乱爆发后受命平叛，先后收复河北、河东、长安、洛阳等地，后又平定仆固怀恩叛乱，击退吐蕃、回纥联军进犯，历仕唐玄宗、肃宗、代宗、德宗四朝，为唐代中兴立下赫赫战功，封汾阳郡王，图形凌烟阁，被尊为“尚父”','忠勇沉稳，宽厚谦逊，识大体顾大局，不居功自傲，极具政治智慧，史称其“权倾天下而朝不忌，功盖一代而主不疑”','唐朝',1,'2026-04-08 15:06:56.791519','2026-04-08 15:06:56.791519','/images/ancient_character_men.webp'),(36,'李光弼','男',708,764,'营州柳城（今辽宁省朝阳市）','契丹族，出身将门，为左羽林大将军李楷洛第四子，唐朝中期杰出军事统帅，是平定安史之乱的核心功臣之一，与郭子仪并称“李郭”，因战功封临淮郡王，晚年遭宦官构陷，愧恨病逝','治军严整，沉稳多谋，刚毅果断，用兵善出奇制胜，军纪威严深得士卒敬畏','唐朝',1,'2026-04-08 15:23:11.820997','2026-04-08 15:23:11.820997','/images/ancient_character_men.webp'),(37,'高仙芝','男','?',756,'高句丽（今中国东北及朝鲜半岛北部一带）','高句丽贵族后裔，其父高舍鸡为唐朝安西军将领，高仙芝少年时随父前往安西都护府，以父荫入仕，凭借军功逐步升迁为安西副都护、四镇都知兵马使，是唐朝中期著名军事将领，曾远征小勃律、击破石国，为怛罗斯之战唐军统帅，安史之乱爆发后受命率军抵御叛军','骁勇果敢，富有谋略，擅长长途奔袭作战，治军有方但存在贪财好利的不足','唐朝',1,'2026-04-08 15:29:37.611546','2026-04-08 15:29:37.611546','/images/ancient_character_men.webp'),(38,'封常清','男','?',756,'蒲州猗氏','出身贫寒，幼年随获罪流放安西的外祖父生活，成年后投身安西军旅，得名将高仙芝赏识逐步获得提拔，后官至安西四镇节度使，多次率军平定西域叛乱，安史之乱爆发后率军东出平叛，因兵力悬殊战败退守潼关，遭宦官边令诚诬陷被处死','坚毅果决，治军严明，勤勉好学，富有军事谋略，虽形貌丑陋、脚有残疾却胸有大志','唐朝',1,'2026-04-08 15:36:46.002062','2026-04-08 15:36:46.002062','/images/ancient_character_men.webp'),(39,'哥舒翰','男','?',757,'安西都护府龟兹（今新疆维吾尔自治区库车市）','突骑施哥舒部落贵族出身，父亲哥舒道元曾任安西副都护，早年投身军旅，在河西边境屡破吐蕃，是唐玄宗时期镇守西北的核心名将，累官至河西节度使、西平郡王。安史之乱爆发后奉命镇守潼关，被唐玄宗强令出关迎战叛军，战败被俘，最终被叛军首领安庆绪杀害。','骁勇果敢，重信守义，治军严明，轻财好施，但晚年嗜酒享乐，行事偏刚愎自用','唐朝',1,'2026-04-08 15:42:38.115277','2026-04-08 15:42:38.115277','/images/ancient_character_men.webp'),(40,'李白','男',701,762,'绵州昌隆县（今四川省江油市，一说为西域碎叶城，今吉尔吉斯斯坦托克马克市）','字太白，号青莲居士，又被称为“谪仙人”，出身商贾家庭，少时博览群书，习剑学道，青年时期漫游各地，曾得举荐入朝任供奉翰林，因遭权贵排挤辞官离京，安史之乱后受永王李璘案牵连被流放，晚年漂泊困顿最终病逝，是中国古代伟大的浪漫主义诗人，被后世尊为“诗仙”。','豪放洒脱、傲岸不羁、浪漫乐观、嗜酒重义，蔑视权贵','唐朝',1,'2026-04-08 15:45:42.361537','2026-04-08 15:45:42.361537','/images/ancient_character_men.webp'),(41,'杜甫','男',712,770,'河南巩县（今河南省巩义市）','出身京兆杜氏分支，祖父为初唐著名诗人杜审言，少年时曾游历吴越、齐赵等地，科举不顺仕途坎坷，恰逢安史之乱爆发，一生多在颠沛流离中度过，创作了大量记录社会动荡、民生疾苦的现实主义诗作，被后世尊为“诗圣”，其作品被称为“诗史”','忧国忧民、心怀苍生、正直坚韧、悲悯宽厚','唐朝',1,'2026-04-08 15:52:52.668190','2026-04-08 15:52:52.668190','/images/ancient_character_men.webp'),(42,'史万岁','男',549,600,'京兆杜陵（今陕西省西安市东南）','北周沧州刺史史静之子，北周时期便从军征战，是隋朝开国名将，先后参与平定尉迟迥之乱、北击突厥、平定江南叛乱等战事，屡立显赫战功，后遭宰相杨素诬陷，被隋文帝杨坚下令处死。','勇猛刚烈，治军宽简，作战时身先士卒，不善阿谀逢迎，恃功自负','隋朝',1,'2026-04-08 15:59:11.800967','2026-04-08 15:59:11.800967','/images/ancient_character_men.webp'),(43,'韩擒虎','男',538,592,'河南郡东垣县（今河南省新安县）','出身将门，为北周骠骑大将军韩雄之子，初仕北周，历任都督、合州刺史等职，封新义郡公。隋朝建立后任庐州总管，受命筹备平陈，开皇八年（588年）作为隋军先锋攻陈，率先攻入陈都建康，生擒陈后主陈叔宝，因功进位上柱国，后官至凉州总管。','勇武有谋，胆识过人，性情慷慨豁达','隋朝',1,'2026-04-08 16:03:35.108362','2026-04-08 16:03:35.108362','/images/ancient_character_men.webp'),(44,'贺若弼','男',544,607,'河南洛阳','出身鲜卑族将门，为北周金州刺史贺若敦之子，初仕北周任寿州刺史，封襄邑县公；隋朝建立后出任吴州总管，参与隋灭陈之战立下赫赫战功，进位上柱国，封宋国公，后期因功高受到朝廷猜忌','勇武善战，富有军事谋略，但居功自矜，喜好夸耀功绩，口无遮拦','隋朝',1,'2026-04-08 16:12:57.506960','2026-04-08 16:12:57.506960','/images/ancient_character_men.webp'),(45,'李春','男','?','?','邢州尧山（今河北省邢台市隆尧县）','隋代杰出造桥工匠，主持设计建造了世界现存年代最久、保存最完整的敞肩石拱桥赵州桥（安济桥），其造桥工艺开创了中国桥梁建造的全新格局，对后世桥梁建筑技术发展影响深远','严谨务实、技艺精湛、勇于创新','隋朝',1,'2026-04-08 16:27:45.824540','2026-04-08 16:27:45.824540','/images/ancient_character_men.webp'),(46,'展子虔','男',545,618,'渤海厌次（今山东省滨州市阳信县）','中国古代杰出画家，历经北齐、北周两朝，入隋后官至朝散大夫、帐内都督，擅长绘制人物、山水、车马、楼阁，其传世作品《游春图》是中国现存最早的卷轴山水画，开创了青绿山水的创作范式，对后世山水画发展影响极为深远。','正史中关于其性格的直接记载较少，相传他潜心钻研画艺，创作态度严谨细腻，淡泊功名利禄，将毕生精力投入绘画艺术的探索与创作中。','隋朝',1,'2026-04-08 16:51:13.809943','2026-04-08 16:51:13.809943','/images/ancient_character_men.webp'),(47,'武则天','女',624,705,'并州文水（今山西省文水县）','唐朝开国功臣武士彟次女，十四岁入唐太宗后宫为才人，唐高宗时期被立为皇后，逐步掌握最高权力，与唐高宗并称“二圣”，高宗驾崩后临朝称制，公元690年称帝，改国号为周，是中国历史上唯一的正统女皇帝，晚年还政于李唐','聪慧机敏，果敢坚毅，兼具极高的政治才能与魄力，行事狠厉果决','唐朝',1,'2026-04-08 16:54:10.599342','2026-04-08 16:54:10.599342','/images/ancient_character_women.webp'),(48,'李隆基','男',685,762,'东都洛阳（今河南省洛阳市）','唐高宗李治与武则天之孙，唐睿宗李旦第三子，初封临淄王，早年发动唐隆政变铲除韦后乱党，拥立父亲李旦复位后被立为太子，公元712年登基为帝。统治前期开创了唐朝极盛的开元盛世，后期怠于政务、宠信奸佞，引发安史之乱，被迫退位为太上皇','前期英明果断、锐意进取、知人善任，晚年骄奢怠惰、好大喜功、猜忌多疑','唐朝',1,'2026-04-08 17:01:13.002859','2026-04-08 17:01:13.002859','/images/ancient_character_men.webp'),(49,'李治','男',628,683,'京兆长安（今陕西省西安市）','唐太宗李世民第九子，嫡出第三子，母为文德顺圣皇后长孙氏，唐朝第三位皇帝。在位前期延续贞观时期的施政举措，开创了永徽之治，先后灭西突厥、百济、高句丽，让唐朝疆域达到鼎盛，后期因身体状况不佳，逐渐令皇后武则天参与朝政，逐步形成二圣临朝的格局。','宽厚仁和，外柔内刚，行事隐忍果决','唐朝',1,'2026-04-08 17:37:04.834535','2026-04-08 17:37:04.834535','/images/ancient_character_men.webp'),(50,'太平公主','女','?',713,'长安（今陕西省西安市）','唐高宗李治与女帝武则天的幼女，唐中宗李显、唐睿宗李旦的胞妹，自幼极受父母兄长宠爱，手握重权权倾朝野，曾联合李隆基发动唐隆政变铲除韦后集团，后因与唐玄宗李隆基争夺权力失败被赐死','聪慧机敏，深谙权谋，极具政治野心，行事果决狠厉，骄纵霸道','唐朝',1,'2026-04-09 10:51:02.909225','2026-04-09 10:51:02.909225','/images/ancient_character_women.webp'),(51,'上官婉儿','女',664,710,'陕州陕县（今河南省三门峡市陕州区）','西汉上官桀后裔，唐代宰相上官仪的孙女，上官仪因起草废武则天诏书获罪被杀后，她随母被配入内廷为婢，因天资聪慧、精于诗文获武则天赏识，长期掌管宫中制诰，有「巾帼宰相」之名，唐中宗时期受封昭容，以皇妃身份执掌内廷与外朝文告，曾主持修文馆、品评天下文士作品，是初唐文坛的核心人物之一','聪慧颖悟，富有才思，权变通达，兼具出色的政治手腕与文学素养','唐朝',1,'2026-04-09 10:59:41.823389','2026-04-09 10:59:41.823389','/images/ancient_character_women.webp'),(52,'李贺','男',790,816,'河南府福昌县昌谷乡（今河南省洛阳市宜阳县）','唐朝宗室郑王李亮后裔，家道中落，自幼聪慧少有诗名，因父亲名晋肃，“晋”与“进”同音，被攻讦不得参加进士科考试，仕途受阻，仅任过从九品奉礼郎，一生穷困多病，是中唐浪漫主义诗歌的代表人物，世称“诗鬼”','敏感多思，孤傲清高，心思细腻，多愁善感，作诗刻苦，常年满怀壮志难酬的愤懑','唐朝',1,'2026-04-09 11:10:58.563655','2026-04-09 11:10:58.563655','/images/ancient_character_men.webp'),(53,'刘禹锡','男',772,842,'河南洛阳','唐朝中期著名文学家、哲学家、政治家，有“诗豪”之称，贞元九年进士及第，参与王叔文主导的永贞革新，革新失败后多次被贬谪，晚年官至太子宾客、检校礼部尚书，文学造诣颇高，与柳宗元并称“刘柳”，与白居易并称“刘白”，留下诸多脍炙人口的诗文作品','乐观旷达，刚毅不屈，锐意进取，豪迈洒脱','唐朝',1,'2026-04-09 11:13:13.360765','2026-04-09 11:13:13.360765','/images/ancient_character_men.webp'),(54,'李商隐','男',813,858,'怀州河内（今河南省沁阳市）','字义山，号玉谿生，晚唐著名诗人，出身没落小官僚家庭，开成二年进士及第，因卷入\"牛李党争\"的政治漩涡，一生仕途困顿，多担任幕僚、低级官吏，文学成就突出，与杜牧并称\"小李杜\"，与温庭筠并称\"温李\"，其无题诗风格秾丽、含蓄朦胧，在文学史上影响深远。','敏感细腻，多情重义，内敛隐忍，心怀家国抱负却终生不得志，情感深沉含蓄。','唐朝',1,'2026-04-09 11:15:33.682613','2026-04-09 11:15:33.682613','/images/ancient_character_men.webp'),(55,'杜牧','男',803,852,'京兆万年（今陕西省西安市）','出身关中名门京兆杜氏，是唐代名臣、史学家杜佑之孙，进士及第后踏入仕途，历任监察御史，黄州、池州、睦州刺史、中书舍人等职，是晚唐杰出的诗人、散文家，与李商隐并称“小李杜”。','刚直敢言，心怀经世济世的抱负，同时性情旷达洒脱，不拘小节。','唐朝',1,'2026-04-09 11:17:34.521240','2026-04-09 11:17:34.521240','/images/ancient_character_men.webp'),(56,'杨勇','男','?',604,'长安（今陕西西安），史载未明确','隋文帝杨坚与文献皇后独孤伽罗的嫡长子，隋朝开国后被册立为皇太子，后遭独孤皇后、晋王杨广等人构陷被废为庶人，隋炀帝杨广即位后被赐死，后追封为房陵王','宽厚仁和，率性随性，生活骄奢，不擅伪装矫饰','隋朝',1,'2026-04-09 11:27:32.865556','2026-04-09 11:27:32.865556','/images/ancient_character_men.webp'),(57,'杨俊','男',571,600,'弘农华阴（今陕西省华阴市）','隋文帝杨坚第三子，母为文献皇后独孤伽罗，初封秦王，历任上柱国、洛州刺史、秦州总管等职，曾率水军参与隋灭陈之战，后因奢侈逾制被隋文帝免官，仅保留王爵，最终被王妃崔氏下毒谋害，谥号孝','仁厚慈爱，崇敬佛道，后期骄奢放纵，喜好声色','隋朝',1,'2026-04-09 11:29:13.244624','2026-04-09 11:29:13.244624','/images/ancient_character_men.webp'),(58,'杨秀','男','?',618,'京兆长安（今陕西省西安市）','隋文帝杨坚第四子，隋炀帝杨广同母弟，母为文献皇后独孤伽罗。初封越王，后改封蜀王，出任益州总管总领西南二十四州军政，因才能出众、手握重兵遭到杨广忌惮，被杨广诬陷谋反而废为庶人长期囚禁，江都之变时被宇文化及杀害。','容貌魁伟、武艺过人，性情骄横暴烈，行事奢靡严苛，行事不拘法度。','隋朝',1,'2026-04-09 11:31:07.857942','2026-04-09 11:31:07.857942','/images/ancient_character_men.webp'),(59,'杨谅','男','?',605,'长安（今陕西省西安市）','隋文帝杨坚第五子，隋炀帝杨广同母弟，为文献皇后独孤伽罗所生，开皇元年受封汉王，后出任并州总管，统领黄河以北五十二州军政事务，隋文帝驾崩后因不满杨广即位举兵反叛，被杨素率军击败后被削爵囚禁','骄纵自负，素有野心，刚愎自用，行事武断','隋朝',1,'2026-04-09 11:32:41.356616','2026-04-09 11:32:41.356616','/images/ancient_character_men.webp'),(60,'杨昭','男',584,606,'隋大兴城（今陕西省西安市）','隋文帝杨坚之孙，隋炀帝杨广嫡长子，生母为萧皇后，初封河南王，隋炀帝即位后被册立为皇太子，大业二年病逝，谥号元德，其子杨侑被拥立为隋恭帝后追尊其为孝成皇帝，庙号世宗','宽厚仁爱，谦和恭谨，有勇力，行事端重，未尝轻易动怒','隋朝',1,'2026-04-09 11:34:16.508808','2026-04-09 11:34:16.508808','/images/ancient_character_men.webp'),(61,'杨暕','男',585,618,'弘农华阴（今陕西省华阴市）','隋炀帝杨广嫡次子，母亲为文献皇后独孤伽罗，初封豫章王，历任扬州总管、河南尹等职，后晋封齐王，早年颇受隋炀帝宠爱，后因行事骄纵越礼失宠，江都之变时与两个儿子一同被宇文化及叛军杀害','骄奢放纵，宠信奸佞，行事逾矩，颇有城府','隋朝',1,'2026-04-09 11:35:39.554517','2026-04-09 11:35:39.554517','/images/ancient_character_men.webp'),(62,'杨杲','男',607,618,'大兴城（今陕西省西安市）','隋炀帝杨广幼子，生母为萧嫔，大业九年受封赵王，曾陪同隋炀帝巡幸江都，江都之变时被叛军杀害，年仅十二岁','聪慧机敏，至孝知礼，容貌俊美，可熟练背诵隋炀帝所作词赋','隋朝',1,'2026-04-09 11:37:03.193043','2026-04-09 11:37:03.193043','/images/ancient_character_men.webp'),(63,'杨弘','男','?',607,'弘农华阴（今陕西省华阴市）','隋朝宗室大臣，隋文帝杨坚从祖弟，北周时期就追随杨坚，是杨坚的核心心腹之一，隋朝建立后受封河间王，先后任沧州刺史、蒲州刺史等职，在地方任职十余年，整肃治安、安抚百姓，政绩突出，隋炀帝即位后被征召入朝，拜太子太保','聪慧明悟，宽厚有器度，兼具文武才干，为官清谨务实，行事果决','隋朝',1,'2026-04-09 11:38:20.334876','2026-04-09 11:38:20.334876','/images/ancient_character_men.webp'),(64,'杨瓒','男',549,591,'弘农华阴（今陕西省华阴市）','北周隋国公杨忠第三子，隋文帝杨坚同母弟，早年仕北周，娶北周武帝宇文邕之妹顺阳公主，封竟陵郡公；隋朝建立后受封滕王，曾任雍州牧等职','容貌俊美，喜好读书，礼贤下士，在北周时便有很高声望，对杨坚代周持反对态度，与杨坚政见不和','隋朝',1,'2026-04-09 11:40:25.465301','2026-04-09 11:40:25.465301','/images/ancient_character_men.webp'),(65,'杨约','男','?','?','弘农华阴','北周汾州刺史杨敷之子，隋朝重臣杨素的异母弟弟，早年以父荫入仕，隋朝建立后深得杨素信任，全程参与杨广夺嫡的谋划，杨广即位后官至内史令，后外任淅阳太守，卒于任上。','深沉狡黠，多谋善算，博学强记，擅长揣摩人心。','隋朝',1,'2026-04-09 11:42:07.220718','2026-04-09 11:42:07.220718','/images/ancient_character_men.webp'),(66,'杨文思','男',538,607,'弘农华阴（今陕西华阴）','出身世家大族弘农杨氏，为北周小冢宰、华山元公杨宽之子，早年入仕北周，历任车骑大将军、洛州刺史等职，受封永宁县公；隋朝建立后，历任魏州刺史、民部尚书、纳言、右光禄大夫等要职，改封正平郡公，任职期间政绩突出，是隋朝重要官员','温和恭谨，富有才干，为官清廉，为政宽厚简约','隋朝',1,'2026-04-09 11:43:50.743063','2026-04-09 11:43:50.743063','/images/ancient_character_men.webp'),(67,'杨文纪','男',545,603,'弘农华阴','出身弘农杨氏望族，为北周小冢宰杨宽之子，初仕北周袭爵华山郡公，杨坚执政时随梁睿征讨王谦有功，入隋后历任资州刺史、宗正卿、荆州总管等职，进位上柱国，为隋初重臣','生性刚正有器局，博学多识，治政宽厚仁惠，官声颇佳','隋朝',1,'2026-04-09 11:45:43.161693','2026-04-09 11:45:43.161693','/images/ancient_character_men.webp'),(68,'牛弘','男',545,610,'安定郡鹑觚县（今甘肃省平凉市灵台县一带）','出身官宦世家，本姓尞，其父为北魏侍中，被朝廷赐姓牛。北周时期袭封临泾公，曾参与修撰国史；隋朝建立后深受隋文帝、隋炀帝信任，历任秘书监、礼部尚书、吏部尚书等职，曾奏请朝廷征集天下散佚书籍，主持修订《五礼》，铨选官员侧重德行才学，是隋初文化制度建设的核心参与者，为隋朝文化事业发展作出了突出贡献。','宽厚仁恕，沉稳好学，为官清正俭朴，行事谨慎大度，平生笃好典籍，虽公务繁杂也手不释卷。','隋朝',1,'2026-04-09 11:47:45.053616','2026-04-09 11:47:45.053616','/images/ancient_character_men.webp'),(69,'李德林','男',530,591,'博陵安平（今河北省衡水市安平县）','出身博陵李氏望族，年少时因才学出众被称为神童，先后仕于北齐、北周，是隋文帝杨坚代周建隋的核心谋划者之一，隋朝建立后官至内史令，参与国家典章制度制定、国史修撰工作，是南北朝末年到隋初著名的文学家、史学家，为《北齐书》作者李百药的父亲','聪敏好学，才思敏捷，治学严谨，为人耿直','隋朝',1,'2026-04-09 11:50:15.395416','2026-04-09 11:50:15.395416','/images/ancient_character_men.webp'),(70,'苏威','男',542,623,'京兆武功（今陕西省咸阳市武功县）','出身关中世家京兆苏氏，是西魏名臣苏绰之子，北周时期已受重用，隋朝建立后成为核心朝臣，为隋文帝时期的“四贵”之一，曾参与制定《开皇律》、推行均田制等重要政务，为开皇之治作出了突出贡献。隋亡后先后依附宇文化及、李密、王世充势力，入唐后未得到任用。','沉稳谨慎，通晓历代典章制度，为政崇尚宽简，但为人圆滑，遇事常存明哲保身的想法，隋末动荡时多次随波逐流依附不同势力。','隋朝',1,'2026-04-09 11:52:42.559701','2026-04-09 11:52:42.559701','/images/ancient_character_men.webp'),(71,'韦世康','男',531,597,'京兆杜陵（今陕西省西安市一带）','出身关中望族京兆韦氏，是北周名士韦夐之子，早年在北魏、北周任职，曾娶北周文帝宇文泰之女襄乐公主，入隋后历任礼部尚书、吏部尚书、荆州总管等要职，政绩突出，是隋文帝时期的重臣，去世后追赠大将军、雍州刺史，谥号为文','沉稳宽厚，清廉俭朴，为人谦逊谨慎，为政宽简，有孝友之名','隋朝',1,'2026-04-09 11:54:58.546851','2026-04-09 11:54:58.546851','/images/ancient_character_men.webp'),(72,'韦洸','男','?',590,'京兆杜陵（今陕西省西安市东南）','北周名将韦孝宽之子，北周时期凭军功累迁柱国，受封襄阳郡公；隋朝建立后先后担任荆州总管、广州总管，曾率军前往岭南安抚当地势力，稳定隋初岭南统治','勇武有谋略，性情宽厚，治军理政都颇得民心','隋朝',1,'2026-04-09 11:56:34.764368','2026-04-09 11:56:34.764368','/images/ancient_character_men.webp'),(73,'韦艺','男',538,597,'京兆杜陵（今陕西省西安市）','出身关中望族京兆韦氏逍遥公房，为北周逍遥公韦夐之子，早年入仕北周，后支持隋文帝杨坚，参与平定尉迟迥之乱，隋朝建立后历任齐州刺史、营州总管，封魏兴郡公，主政地方和边地期间政绩突出，有效安抚东北各族，深得民心。','沉稳宽厚，勇武有谋，为政清简','北周至隋朝',1,'2026-04-09 11:58:13.619556','2026-04-09 11:58:13.619556','/images/ancient_character_men.webp'),(74,'韦冲','男',540,605,'京兆杜陵（今陕西省西安市一带）','出身关中望族京兆韦氏逍遥公房，为北周逍遥公韦夐之子、名将韦孝宽之侄，初仕北周，隋朝建立后历任南宁州总管、营州总管，妥善安抚边境各族，后入朝任民部尚书，封安阳县侯','宽厚仁恕，善于抚绥，行事沉稳，深得民心','隋朝',1,'2026-04-09 11:59:55.174694','2026-04-09 11:59:55.174694','/images/ancient_character_men.webp'),(75,'韦寿','男',549,590,'京兆杜陵（今陕西省西安市）','出身关中望族京兆韦氏，是北周名将韦孝宽第四子，北周时期以父荫入仕，受封永安县侯；隋朝建立后历任恒州刺史、毛州刺史、户部侍郎、并州总管等职，治绩突出，晋封滑国公','品性方正耿直，事母至孝，为人沉稳有器量，兼具治事才干','隋朝',1,'2026-04-09 12:01:59.685343','2026-04-09 12:01:59.685343','/images/ancient_character_men.webp'),(76,'柳机','男',539,594,'河东解县（今山西省运城市盐湖区解州镇）','出身门阀世族河东柳氏，为北周名臣柳庆之子，自幼博览经史，早年出仕北周，累迁至华州刺史，受封平齐县公，北周末年深得丞相杨坚信任，隋朝建立后历任纳言、卫州刺史、冀州刺史等职，治政有方，去世后追赠大将军、青州刺史，谥号为简','宽厚简素，器度沉雅，行事方正，治民宽惠，深得治下百姓爱戴','隋朝',1,'2026-04-09 12:03:43.792375','2026-04-09 12:03:43.792375','/images/ancient_character_men.webp'),(77,'柳述','男',570,608,'河东解县（今山西省运城市永济市一带）','出身门阀世族河东柳氏，是北周尚书左仆射柳庆之孙、隋朝华州刺史柳机之子，成年后迎娶隋文帝杨坚幼女兰陵公主杨阿五，深得隋文帝宠信，累官至兵部尚书、参掌机密，是隋文帝晚年的核心重臣之一，因与权臣杨素、后来的隋炀帝杨广交恶，隋文帝驾崩后被杨广治罪流放岭南','聪慧机敏，通晓时务，但恃宠骄横，气量狭隘，轻侮同僚，行事刚直自负','隋朝',1,'2026-04-09 12:05:24.279883','2026-04-09 12:05:24.279883','/images/ancient_character_men.webp'),(78,'柳旦','未知',0,NULL,'未知','未知','未知','未知',1,'2026-04-09 12:06:53.263757','2026-04-09 12:06:53.263757','/images/ancient_character_men.webp'),(79,'柳肃','男',544,615,'河东解县（今山西省临猗县一带）','出身世家大族河东柳氏，是北周骠骑大将军柳庆之子，早年入仕北周任记室参军，隋朝建立后历任太子内舍人、太子洗马，是废太子杨勇的核心属官，杨勇被废后受牵连去职，隋炀帝继位后重新获任用，先后任工部侍郎、光禄少卿等职，以理政才干著称。','聪慧机敏，行事严谨，善于言辞应对，处事稳重有法度','隋朝',1,'2026-04-09 12:08:13.163336','2026-04-09 12:08:13.163336','/images/ancient_character_men.webp'),(505,'柳雄亮','未知',0,NULL,'未知','未知','未知','未知',1,'2026-04-09 12:38:17.192539','2026-04-09 12:38:17.192539','/images/ancient_character_men.webp'),(506,'柳謇之','男','?','?','河东解县（今山西省运城市）','出身世家河东柳氏，历仕北周、隋朝两朝，早年以明经入仕北周，隋朝建立后多次负责接待周边藩国使节，后出任齐王杨暕长史，因杨暕获罪受到牵连被除名，隋炀帝时期被重新起用，江都之变后被宇文化及任命为内史令，最终卒于乱军之中','疏朗有才，仪范端雅，善于辞令，性情谦和，喜好饮酒交结宾客','隋朝',1,'2026-04-09 13:10:15.946286','2026-04-09 13:10:15.946286','/images/ancient_character_men.webp'),(507,'柳昂','男','?','?','河东解县（今山西省运城市解州镇一带）','出身世家大族河东柳氏，为北周大臣柳敏之子，历仕北周、隋朝，北周时期官至吏部中大夫，杨坚执掌北周朝政后得其亲信，隋朝建立后出任潞州刺史，曾上书隋文帝提议推行劝学行礼之政，获文帝采纳并推广天下，最终卒于任上','沉稳机敏，有器量格局','隋朝',1,'2026-04-09 13:11:50.107486','2026-04-09 13:11:50.107486','/images/ancient_character_men.webp'),(508,'柳调','男','?','?','河东解县（今山西运城）','出身门阀河东柳氏，为北周名臣柳庆之孙、隋朝冀州刺史柳机之子，隋文帝时起家任秘书郎，隋炀帝时升任尚书左司郎，隋亡后入长安归顺唐朝，被唐高祖李渊任命为秘书丞，不久后去世','刚直方正，恪尽职守，颇有父风','隋唐',1,'2026-04-09 13:13:15.179259','2026-04-09 13:13:15.179259','/images/ancient_character_men.webp'),(509,'韩僧寿','男','?','?','河南东垣（今河南新安）','北周名将韩雄次子，隋朝名将韩擒虎之弟，早年出仕北周，以军功累迁骠骑将军，隋朝建立后加封公爵，常年镇守北方边境防御突厥，跟随杨素击破突厥，历任大将军、灵州总管、江都太守等职，先后受封寿光县公、江都郡公、新蔡郡公','勇武剽悍，忠勇果毅，善骑射，以武略见长','隋朝',1,'2026-04-09 13:14:23.070226','2026-04-09 13:14:23.070226','/images/ancient_character_men.webp'),(510,'韩洪','男','?','?','河南东垣（今河南新安东）','隋朝著名将领，是西魏北周名将韩雄第三子，隋朝开国名将韩擒虎的胞弟，早年出仕北周，凭借军功不断升迁，隋朝建立后多次领兵平定地方叛乱、出击突厥，后因作战失利获罪被贬，隋炀帝即位后被起复为陇西太守，不久后去世','骁勇果敢，膂力过人，勇武善战','隋朝',1,'2026-04-09 13:15:37.926630','2026-04-09 13:15:37.926630','/images/ancient_character_men.webp'),(511,'达奚长儒','男','?','?','代郡平城','鲜卑族，出身将门，祖父达奚眷为北魏安西将军，父亲达奚庆为北周骠骑大将军，历仕西魏、北周、隋朝，是南北朝至隋代名将，多次领军击退突厥进犯，立下诸多战功，最终病逝于荆州总管任上','胆气过人，忠勇果毅，临危不乱，身先士卒','隋朝',1,'2026-04-09 13:16:43.750304','2026-04-09 13:16:43.750304','/images/ancient_character_men.webp'),(512,'宇文述','男',547,617,'代郡武川（今内蒙古武川县）','北周上柱国宇文盛长子，隋朝开国重臣，隋炀帝杨广的心腹，早年效力北周，参与平定尉迟迥叛乱，后助力杨广夺嫡，杨广继位后深得宠信，参与攻灭陈朝、征讨高句丽，是隋末权臣宇文化及的父亲','生性恭谨沉稳，善于逢迎揣摩上意，趋炎附势，深得君主信任','隋朝',1,'2026-04-09 13:18:40.735088','2026-04-09 13:18:40.735088','/images/ancient_character_men.webp'),(513,'郭衍','男','?',611,'太原介休','出身太原郭氏，历仕北周、隋朝，早年在北周以军功升任大将军，入隋后参与平定南陈，主持开凿广通渠漕运工程，力挺晋王杨广夺储，隋炀帝即位后深受宠信，官至左武卫大将军，封武山郡公','骁勇善骑射，长于政务，性情谄媚，惯于迎合上意','隋朝',1,'2026-04-09 13:20:17.379616','2026-04-09 13:20:17.379616','/images/ancient_character_men.webp'),(514,'王韶','男',1030,1081,'江州德安（今江西九江德安）','进士出身，北宋著名将领，是熙河开边的核心主导者，为北宋开拓河湟地区千里疆土，对西夏形成夹击战略态势，官至观文殿学士、枢密副使','富于谋略，果毅敢为，胸有全局经略','北宋',1,'2026-04-09 13:22:21.185670','2026-04-09 13:22:21.185670','/images/ancient_character_men.webp'),(515,'元岩','男',531,593,'河南洛阳','出身北魏宗室，为北魏景穆帝拓跋晃后裔，历仕西魏、北周、隋朝，是隋朝开国名臣，隋初任兵部尚书，后出为益州长史辅佐蜀王杨秀','刚正不阿，鲠直有节，豁朗通达，喜好儒雅','隋朝',1,'2026-04-09 13:27:16.035502','2026-04-09 13:27:16.035502','/images/ancient_character_men.webp'),(516,'刘行本','男','?','?','沛（今江苏省徐州市沛县）','出身官宦世家，伯父为南朝著名学者刘瓛，早年出仕南朝梁，后入北周任职，隋朝建立后受隋文帝重用，历任谏议大夫、黄门侍郎、邠州刺史等职，是隋代知名直臣','刚直耿介，清正守法，敢于直言进谏','隋朝',1,'2026-04-09 13:28:37.620738','2026-04-09 13:28:37.620738','/images/ancient_character_men.webp'),(517,'梁毗','男','?',602,'安定乌氏','出身安定梁氏，历仕西魏、北周、隋三朝，隋文帝时期历任大理寺卿、西宁州刺史、御史大夫等职，以直谏弹劾权贵闻名，曾多次公开揭发权臣杨素的不法行为，是隋代著名的直臣','刚正不阿，耿直敢言，清正无私','隋朝',1,'2026-04-09 13:30:10.177011','2026-04-09 13:30:10.177011','/images/ancient_character_men.webp'),(518,'柳彧','男','?','?','河东解县（今山西省运城市盐湖区解州镇）','出身河东柳氏，早年出仕北周，隋朝建立后官至治书侍御史，因多次直言弹劾权贵、进谏朝政得到隋文帝器重，隋炀帝时遭权臣杨素陷害被贬，最终卒于贬所怀远镇','刚直不阿，好学博闻，不避权贵，敢于直言','隋朝',1,'2026-04-09 13:31:41.136424','2026-04-09 13:31:41.136424','/images/ancient_character_men.webp'),(519,'赵绰','男','?','?','河东（今山西省永济市）','南北朝后期出仕北周，隋朝建立后担任司法官员，历任大理丞、大理正、刑部侍郎，是隋初著名的守法名臣，多次坚持依法断案，甚至顶撞隋文帝纠正不当裁决','刚毅正直，恪守法度，不畏皇权','隋朝',1,'2026-04-09 13:33:47.649599','2026-04-09 13:33:47.649599','/images/ancient_character_men.webp'),(520,'裴肃','男','?',808,'河东闻喜（今山西省运城市闻喜县）','出身河东裴氏，唐代中期官员，早年以明经入仕，历任地方与中央多个官职，后官至浙东观察使，任内平定地方盗贼起事，治理地方颇有政绩。','为官刚正，理政宽厚，体恤百姓','唐朝',1,'2026-04-09 13:35:01.997630','2026-04-09 13:35:01.997630','/images/ancient_character_men.webp'),(521,'樊子盖','男',545,616,'庐江安丰（今安徽省霍邱县）','出身庐江樊氏，初仕北齐，后归降北周，入隋后历任郢州刺史、武威太守、户部尚书等要职，深受隋炀帝信任，曾率军平定杨玄感叛乱，多次领兵镇压隋末农民起义','忠君笃诚，清谨自守，不谋私财，驭下严苛','隋朝',1,'2026-04-09 13:36:24.443479','2026-04-09 13:36:24.443479','/images/ancient_character_men.webp'),(522,'史祥','男','?','?','朔方郡（今内蒙古自治区杭锦旗北）','出身北周将门，父亲为北周骠骑大将军史宁，早年效力北周，隋朝建立后出仕为官，曾参与隋灭陈之战、征讨突厥，历任多州刺史、总管，后官至左卫将军，江都之变后依附宇文化及，不久败亡','谦恭有度，兼具文武才干','隋朝',1,'2026-04-09 13:37:53.434929','2026-04-09 13:37:53.434929','/images/ancient_character_men.webp'),(523,'元寿','男',549,611,'河南洛阳','出身北魏宗室，为北魏昭成帝拓跋什翼犍后裔，早年效力北周，入隋后历任尚书左丞、太常卿、内史令等职，大业七年随隋炀帝征辽东，途中病卒，赠尚书右仆射。','性仁孝，通达干练，端直有谋，居官称职','隋朝',1,'2026-04-09 13:39:46.307928','2026-04-09 13:39:46.307928','/images/ancient_character_men.webp'),(524,'杨义臣','男','?',617,'太安狄那（今山西省寿阳县）','本姓尉迟氏，鲜卑族，北周太保尉迟纲之孙，隋定州总管尉迟崇之子，因父功被隋文帝杨坚赐姓杨氏，自幼养于宫中，是隋朝名将，历仕北周、隋两朝，先后参与平定尉迟迥之乱、北击突厥、出征高句丽、平定杨玄感叛乱，隋末率军镇压农民起义，后遭隋炀帝猜忌被征召回朝，不久病逝','谨慎忠厚，骁勇善战，富有将略','隋朝',1,'2026-04-09 13:41:41.799894','2026-04-09 13:41:41.799894','/images/ancient_character_men.webp'),(525,'卫玄','未知',0,NULL,'未知','未知','未知','未知',1,'2026-04-09 14:02:45.333375','2026-04-09 14:02:45.333375','/images/ancient_character_men.webp'),(526,'王世充','男','?',621,'新丰（今陕西省西安市临潼区东北），祖籍西域','隋末割据势力首领，原为隋朝将领，早年靠军功逐步升迁，官至江都通守，曾奉命镇压隋末农民起义，隋炀帝遇弑后占据洛阳，先拥立后废黜隋恭帝杨侗，自立为帝，国号郑，公元621年被秦王李世民率领的唐军击败，投降唐朝，不久被仇家独孤修德刺杀','猜忌多疑，诡诈善变，好听谗言，好沽虚名','隋朝（隋末割据建立郑政权）',1,'2026-04-09 17:14:13.208638','2026-04-09 17:14:13.208638','/images/ancient_character_men.webp'),(528,'刘权','男','?','?','彭城丰县（今江苏徐州丰县）','出身北朝官宦世家，父亲刘矩为北齐太尉，先后出仕北齐、北周，入隋后参与隋灭陈之战，多次平定地方叛乱，后出任南海太守，镇守岭南，官至金紫光禄大夫','少有侠气，重信守诺，为官刚正，治政威惠并施','隋朝',1,'2026-04-10 09:59:33.968113','2026-04-10 09:59:33.968113','/images/ancient_character_men.webp'),(529,'李圆通','男','?',610,'京兆泾阳（今陕西泾阳）','隋朝官员，早年为隋文帝杨坚家奴，随杨坚平定尉迟迥叛乱，隋朝建立后历任尚书左丞、刑部尚书、兵部尚书，曾参与废黜太子杨勇，后因弹劾得罪宇文述被免官，不久卒于任上','强悍勇武，严谨正直，不徇私情','隋朝',1,'2026-04-10 10:01:05.374134','2026-04-10 10:01:05.374134','/images/ancient_character_men.webp'),(530,'陈茂','男','?','?','河东猗氏（今山西省运城市临猗县）','北周至隋朝时期官员，早年即为隋文帝杨坚的心腹属官，北周时跟随杨坚平定尉迟迥叛乱，隋朝建立后历任给事黄门侍郎、益州长史、陕州刺史，受封魏城县开国男','质朴正直，恭谨畏慎','隋朝',1,'2026-04-10 10:03:05.284624','2026-04-10 10:03:05.284624','/images/ancient_character_men.webp'),(531,'张定和','男','?',609,'京兆万年','隋朝著名将领，出身寒微，早年投身军旅，参与隋朝平陈之战，后多次平定地方叛乱、立下战功，累迁至柱国、武候大将军，大业五年随隋炀帝征讨吐谷浑时战死沙场','慷慨有壮志，骁勇善战，轻财重义','隋朝',1,'2026-04-10 10:05:13.730629','2026-04-10 10:05:13.730629','/images/ancient_character_men.webp'),(532,'张淵','男','?','?','京兆冯翊','北魏时期知名天文学家、方术士，原为胡夏政权赫连昌僚属，北魏攻灭胡夏后入仕北魏，官至骠骑将军，著有天文作品《观象赋》，精通天文占候之术','史无明载，记载其潜心术数，专精天文之学','北魏',1,'2026-04-10 10:07:11.120872','2026-04-10 10:07:11.120872','/images/ancient_character_men.webp'),(533,'麦铁杖','男','?',612,'始兴（今广东省韶关市始兴县）','早年骁勇有力，可日行五百里，因聚众为盗被擒，没为官奴，后仕于陈朝，陈朝灭亡后入隋朝，追随杨素平定江南叛乱、汉王杨谅叛乱，屡立战功，官至右屯卫大将军，公元612年随隋炀帝征高句丽时力战战死，追赠光禄大夫、宿国公','爽朗放达，好酒重义，骁勇果敢，忠烈轻生','隋朝',1,'2026-04-10 10:09:19.036067','2026-04-10 10:09:19.036067','/images/ancient_character_men.webp'),(534,'沈光','男',591,618,'吴兴（今浙江省湖州市）','出身南朝官宦家庭，父亲沈君道曾任南陈吏部侍郎，陈亡后迁居长安，隋大业年间应募入骁果军，深得隋炀帝宠遇，江都之变隋炀帝被宇文化及弑杀后，沈光与同僚图谋诛杀宇文化及报仇，事发后战死','不拘小节，重义轻生，骁勇忠烈','隋朝',1,'2026-04-10 10:10:42.826450','2026-04-10 10:10:42.826450','/images/ancient_character_men.webp'),(535,'来护儿','男','?',618,'江都（今江苏省扬州市）','出身将门，隋朝名将，早年投身军旅，参与平定南陈，后多次领军征讨高句丽，因功封荣国公，深受隋文帝、隋炀帝信任，江都之变时被宇文化及杀害','骁勇有谋，忠勇刚正，重信守义','隋朝',1,'2026-04-10 10:12:17.091380','2026-04-10 10:12:17.091380','/images/ancient_character_men.webp'),(536,'鱼俱罗','男','?',613,'冯翊下邽（今陕西省渭南市）','隋朝著名将领，早年仕北周任亲卫，入隋后跟随杨广参与灭陈之战，先后平定江南叛乱、击破突厥，镇守北疆，因天生重瞳的异相被隋炀帝猜忌，最终于大业九年获罪被斩','勇猛强悍，膂力过人，性情刚直','隋朝',1,'2026-04-10 10:14:56.867421','2026-04-10 10:14:56.867421','/images/ancient_character_men.webp'),(537,'陈棱','男','?',619,'庐江襄安（今安徽巢湖）','隋朝著名将领，出身将门，其父陈岘原为南朝陈将领，陈亡后入隋任职。陈棱早年熟习军旅，以军功升迁，隋炀帝时曾任虎贲郎将，奉命率军远征流求（今台湾），是正史记载中原王朝经略台湾的标志性事件，后累迁至左御卫大将军，隋末镇守江都，江都之变后拒绝依附江淮义军，最终被杜伏威击败杀害。','沉毅果敢，有勇有谋','隋朝',1,'2026-04-10 10:16:24.614990','2026-04-10 10:16:24.614990','/images/ancient_character_men.webp'),(538,'王辩','男','?',613,'冯翊蒲城（今陕西省渭南市大荔县）','出身将门，祖父王禽为北魏大将军、南兖州刺史，父亲王颖为北周陈留太守；北周时起家都督，隋朝建立后历任车骑将军、通议大夫、武贲郎将，参与隋灭陈之战，后多次率军镇压隋末农民起义，大业九年（613年）杨玄感叛乱时，战死在平叛途中。','性情通达，喜好结交招引贤士，骁勇善战，身先士卒，深得士人拥戴','隋朝',1,'2026-04-10 10:18:51.228162','2026-04-10 10:18:51.228162','/images/ancient_character_men.webp'),(539,'周罗睺','男','?',605,'九江寻阳（今江西九江）','南北朝至隋朝时期著名将领，出身将门，早年出仕南朝陈，多次领兵抵御北朝进攻，陈朝灭亡后降隋入仕，先后参与平定江南叛乱、防御突厥、征讨汉王杨谅叛乱等战事，最终在平叛作战中中箭战死','勇武过人，倜傥豪爽，精晓兵略，忠勇有节','南朝陈、隋朝',1,'2026-04-10 10:20:34.387410','2026-04-10 10:20:34.387410','/images/ancient_character_men.webp'),(540,'周法尚','男',556,614,'汝南安阳（今河南省平舆县一带）','出身将门，父亲为南梁定州刺史周炅，早年出仕南朝陈，后归降北周，隋朝建立后历任黄州总管、桂州总管、右武卫将军等职，先后参与平定岭南叛乱、征讨高句丽等战事，是隋代著名将领','果敢刚毅，有风节，熟谙兵略，治军严明','隋朝',1,'2026-04-10 10:22:38.324450','2026-04-10 10:22:38.324450','/images/ancient_character_men.webp'),(541,'李景','男','?',618,'天水成纪','北周至隋朝时期将领，父亲李超为北周大将军，早年追随北周武帝攻灭北齐，隋朝建立后参与灭陈之战、征讨高句丽等战事，隋末乱世中坚守幽州','刚正耿直，有胆略，骁勇善战，深得军心','隋朝',1,'2026-04-10 10:25:18.176234','2026-04-10 10:25:18.176234','/images/ancient_character_men.webp'),(542,'慕容三藏','男',546,613,'昌黎棘城（今辽宁省义县西北）','慕容鲜卑后裔，东魏名将慕容绍宗之子，历仕北齐、北周、隋三朝，早年随父征战，北齐灭亡后入仕北周，隋朝代周后为隋效力，参与平定岭南地方叛乱，长期镇守边境，任职期间多有政绩','骁勇有谋，沉稳果决，为政清明','隋朝',1,'2026-04-10 10:27:06.142003','2026-04-10 10:27:06.142003','/images/ancient_character_men.webp'),(543,'薛世雄','男',555,617,'河东汾阴（今山西省万荣县）','南北朝至隋朝时期名将，出身河东薛氏将门，年少随北周武帝平定北齐，隋朝建立后历任都督、仪同三司、右监门郎将等职，先后参与征讨吐谷浑、高句丽，隋末奉命镇压河北农民起义，被窦建德击败后退回幽州，不久发病去世','谨慎厚重，治军严整，勇武善战，为官有惠政','隋朝',1,'2026-04-10 10:29:54.134427','2026-04-10 10:29:54.134427','/images/ancient_character_men.webp'),(544,'王仁恭','男',558,617,'天水上邽（今甘肃省天水市）','出身将门，历仕北周、隋朝，为隋朝著名将领，曾参与隋灭陈之战，跟随杨素击破突厥，官至左武卫大将军、光禄大夫，后奉命镇守马邑，隋末大乱时被刘武周发动兵变杀害','刚毅严谨，骁勇善战','隋朝',1,'2026-04-10 10:31:53.983578','2026-04-10 10:31:53.983578','/images/ancient_character_men.webp'),(545,'权武','男','?','?','天水显亲（今甘肃秦安）','出身北周将门，父亲权庆曾任北周开府仪同三司，早年仕北周，袭爵齐郡公，北周禅代隋后，入朝隋为官，历任大将军、豫州总管、潭州总管等职，曾因徇私贪污、造图谶等事获罪被隋文帝免官，后又被朝廷再度起用，《隋书》有其传记记载。','骁勇善射，不拘法度，贪财好利','隋朝',1,'2026-04-10 10:33:42.239190','2026-04-10 10:33:42.239190','/images/ancient_character_men.webp'),(546,'吐万绪','男','?',613,'京兆栎阳（今陕西省西安市临潼区东北）','出身代北鲜卑吐万氏，北周时期袭爵元寿县公，隋朝建立后历任地方要职，参与平定南陈、江南叛乱，隋炀帝时期先后参与征伐高句丽、平定杨玄感叛乱，后奉命镇压隋末农民起义，因进军节奏不合隋炀帝心意被问责，最终忧愤而死','勇武有谋，刚正有识','隋朝',1,'2026-04-10 10:35:26.653969','2026-04-10 10:35:26.653969','/images/ancient_character_men.webp'),(547,'董纯','男','?',613,'陇西成纪','出身将门，北周、隋朝时期将领，早年效力北周，随周武帝攻灭北齐，入隋后参与平陈之战、征讨突厥等战事，深受两代君主信任，大业年间奉命镇压农民起义，后遭人诬陷被隋炀帝赐死','骁勇有才，谨厚持重','隋朝',1,'2026-04-10 10:37:49.019094','2026-04-10 10:37:49.019094','/images/ancient_character_men.webp'),(548,'赵才','男',547,618,'张掖酒泉（今甘肃省酒泉市）','出身陇右赵氏，早年出仕北周，隋朝建立后历任左武卫大将军等职，曾参与平定南陈、北击突厥，多次随隋炀帝出征，因谏阻隋炀帝巡幸江都触怒炀帝，隋末江都之变后被宇文化及杀害','粗犷耿直，骁勇善战，直言敢谏，不事阿谀','隋朝',1,'2026-04-10 10:39:14.939434','2026-04-10 10:39:14.939434','/images/ancient_character_men.webp'),(549,'李谔','男','?','?','赵郡（今河北赵县）','历经北齐、北周、隋三朝，隋代官员、文论家，早年仕北齐任中书舍人，北周灭齐后入仕北周，任天官都上士，隋朝建立后受隋文帝重用，历任比部侍郎、考功侍郎，迁治书侍御史，曾上书抨击齐梁以来浮华绮靡的文风，推动文风改革，后以年老辞官，卒于家中','公正刚直，通达世务','隋朝',1,'2026-04-10 10:41:16.520362','2026-04-10 10:41:16.520362','/images/ancient_character_men.webp'),(550,'鲍宏','男','?','?','东海郯县（今山东省郯城县）','出身官宦世家，早年出仕南朝梁，后相继效力于北齐、北周，隋朝建立后受隋文帝杨坚信任，参与修订礼制与律令，历任地方刺史，封平遥县伯','性情温雅，博通经史，素有令誉','南北朝至隋朝',1,'2026-04-10 10:43:16.356484','2026-04-10 10:43:16.356484','/images/ancient_character_men.webp'),(551,'裴政','男','?','?','河东闻喜（今山西闻喜）','出身河东裴氏，历仕南朝梁、北周、隋朝，是隋代著名法律家，受隋文帝诏令主持修订《开皇律》，为隋朝初年法制建设做出重要贡献','聪明博闻，刚正不阿，清廉公正，明习政务','隋朝',1,'2026-04-10 10:44:50.439349','2026-04-10 10:44:50.439349','/images/ancient_character_men.webp'),(552,'柳庄','男','?',591,'河东解县（今山西省运城市）','出身门阀河东柳氏，历仕南朝西梁、隋朝，西梁时期曾任中书舍人、鸿胪卿，力主西梁归附隋朝，入隋后官至给事黄门侍郎、开府仪同三司，深受隋文帝杨坚信任。','少有远量，明识通达，博览多识，谙练典章','隋朝',1,'2026-04-10 10:46:45.047368','2026-04-10 10:46:45.047368','/images/ancient_character_men.webp'),(553,'源师','男','?','?','河南洛阳','出身北魏鲜卑河西源氏，为北魏名臣源贺后裔，历仕北齐、北周、隋三朝，北齐时曾任尚书左外兵郎中，北周灭齐后入仕北周，隋朝建立后历任尚书右丞、冀州长史、大理少卿等职','谨慎正直，干练明达，恪尽职守','隋朝',1,'2026-04-10 10:48:35.548705','2026-04-10 10:48:35.548705','/images/ancient_character_men.webp'),(554,'郎茂','男',541,615,'恒山新市（今河北省新乐市）','出身官宦世家，父亲郎基为北齐颍川太守，先后历仕北齐、北周，隋朝建立后官至尚书左丞，参与修订隋朝律令典制，隋末卒于绛郡司马任上','雅正谨慎，明晓法令，恪勤职守','隋朝',1,'2026-04-10 10:50:39.757786','2026-04-10 10:50:39.757786','/images/ancient_character_men.webp'),(555,'高构','男','?',605,'北海郡（今山东省寿光市一带）','南北朝至隋朝时期官员，早年出仕北齐，北齐灭亡后入北周任职，隋朝建立后出仕隋朝，历任多职，以知人善鉴闻名，曾举荐后来成为唐代名臣的房玄龄、杜如晦','聪慧机敏，生性诙谐，刚正不阿，不附权贵，善于鉴别人才','隋朝',1,'2026-04-10 10:53:10.623455','2026-04-10 10:53:10.623455','/images/ancient_character_men.webp'),(556,'张虔威','男','?','?','清河东武城','出身清河张氏，为北齐兖州刺史张晏之之子，历仕北齐、北周、隋三朝，隋代曾任谒者大夫、并州司马等职，被列入隋代循吏','聪慧明悟，干练有能，清廉俭约','隋朝',1,'2026-04-10 10:54:23.344894','2026-04-10 10:54:23.344894','/images/ancient_character_men.webp'),(557,'荣毗','男','?','?','北平无终（今河北省遵化市一带）','出身北朝官宦世家，父亲荣权曾任北魏兵部尚书，早年出仕北周，官至内史下大夫，隋朝建立后历任侍御史、治书侍御史、并州长史等职，为官以严明执法著称','刚直不阿，不畏权贵，奉公守正','隋朝',1,'2026-04-10 10:55:58.180397','2026-04-10 10:55:58.180397','/images/ancient_character_men.webp'),(558,'荣建绪','男','?','?','北平无终（今河北省唐山市玉田县一带）','出身北平荣氏，是北周御正中大夫荣权长子，历仕北魏、北周、隋三朝，北周时官至司宪大夫，入隋后历任始州刺史等职，与隋代名臣杨素交厚','秉性鲠直，守正不阿','隋朝',1,'2026-04-10 10:57:45.986683','2026-04-10 10:57:45.986683','/images/ancient_character_men.webp'),(559,'陆知命','男',548,614,'吴郡富春（今浙江省杭州市富阳区）','出身江南名门吴郡陆氏，南北朝时期出仕南陈，隋灭陈后入仕隋朝，曾游说反叛的高智慧部归降，受隋文帝信任，任治书侍御史，为官纠举不法，隋炀帝时随驾征讨高句丽，最终卒于江都','耿直方正，好学博闻，直言敢谏，不附权贵','隋朝',1,'2026-04-10 10:59:13.661070','2026-04-10 10:59:13.661070','/images/ancient_character_men.webp'),(560,'房彦谦','男',541,613,'齐州临淄（今山东省淄博市）','出身清河房氏官宦世家，是唐代名相房玄龄的父亲，历仕北魏、北齐、隋朝三朝，曾任监察御史、长葛县令等职，为官素有清名，是北朝至隋时期的知名官员','清雅正直，不附权贵，廉洁奉公，淡泊名利','隋朝',1,'2026-04-10 11:01:04.990106','2026-04-10 11:01:04.990106','/images/ancient_character_men.webp'),(561,'虞世基','男',558,618,'会稽余姚（今浙江余姚）','南朝陈太子中庶子虞荔长子，初仕南朝陈，任尚书左丞等职，陈亡后入仕隋朝，深得隋炀帝信任，官至内史侍郎参掌朝政，江都之变时与隋炀帝一同被宇文化及诛杀','阿谀顺旨，贪婪聚财，怯懦避事','隋朝',1,'2026-04-10 11:03:13.444115','2026-04-10 11:03:13.444115','/images/ancient_character_men.webp'),(562,'裴蕴','男','?',618,'河东闻喜（今山西省运城市闻喜县）','出身魏晋名门河东裴氏，早年效力于南陈，隋灭陈后入仕隋朝，受隋炀帝宠信，官至御史大夫，曾主持搜括隐户等政务，江都之变时被宇文化及叛军诛杀。','机敏明辩，善于揣摩上意，阿谀逢迎','隋朝',1,'2026-04-10 11:05:08.502107','2026-04-10 11:05:08.502107','/images/ancient_character_men.webp'),(563,'裴矩','男',547,627,'河东闻喜（今山西省运城市闻喜县）','出身魏晋名门河东裴氏，历仕北齐、北周、隋、唐四朝，隋朝时主持经略西域，撰成记载西域风土地理的《西域图记》，为隋经营西域提供了重要依据，隋末动乱后降唐，官至民部尚书','谙练政务，富有谋略，懂得审时度势，入唐后能犯颜直谏','隋唐时期，卒于唐朝',1,'2026-04-10 11:07:49.608039','2026-04-10 11:07:49.608039','/images/ancient_character_men.webp'),(564,'宇文恺','男',555,612,'夏州朔方（今陕西省靖边县北）','出身鲜卑宇文氏，为北周大司徒宇文贵之子，是隋代著名建筑工程学家，曾主持修建隋大兴城、仁寿宫、东都洛阳城等重大工程，历任营宗庙副监、工部尚书等职','好学博识，巧思过人，沉深有谋','隋朝',1,'2026-04-10 11:10:35.707702','2026-04-10 11:10:35.707702','/images/ancient_character_men.webp'),(565,'阎毗','男',563,613,'榆林盛乐（今内蒙古自治区和林格尔县西北）','出身北周官僚世家，为北周上柱国阎庆之子，娶北周武帝宇文邕之女清都公主；入隋后历任殿内少监、将作少监等职，擅长工程营造、书画工艺，曾参与修筑长城、整治运河、营造隋代车舆仪仗等事务，大业九年随隋炀帝征高句丽，卒于途中','巧慧多思，谙熟典制，善伺上意','隋朝',1,'2026-04-10 11:12:47.997273','2026-04-10 11:12:47.997273','/images/ancient_character_men.webp'),(566,'何稠','男','?','?','蜀郡郫县（今四川省成都市郫都区）','出身工艺世家，南北朝至隋唐时期著名工艺家、建筑家，父亲何通善琢玉，叔父为北周著名学者何妥，自幼承传家学，历仕北周、隋、唐三朝，曾主持隋代舆服羽仪、宫苑陵寝的营造，还曾创制器械、搭建辽东行军浮桥，精通织染工艺，技艺冠绝当时。','聪慧巧思，干练务实，心思缜密','隋唐',1,'2026-04-10 11:14:43.943557','2026-04-10 11:14:43.943557','/images/ancient_character_men.webp'),(567,'王劭','男','?','?','太原晋阳（今山西太原）','南北朝至隋朝著名史学家，出身官宦世家，历仕北齐、北周、隋三朝，隋朝时官至著作郎，长期主持修撰国史，著有《齐志》《隋书》《读书记》等史学著作','沉默好学，博闻强记，喜好附会符瑞，立论多有诡诞之处','隋朝',1,'2026-04-10 11:16:37.489757','2026-04-10 11:16:37.489757','/images/ancient_character_men.webp'),(568,'袁充','男',544,618,'陈郡阳夏（今河南太康）','出身南朝高门士族，祖父袁昂为南朝梁司空，父亲袁君正为南朝梁吴郡太守，早年历仕南朝陈，陈亡后入仕隋朝，精通天文历算，官至隋朝秘书令，常以符命天象迎合君主心意获取宠信，江都之变时被宇文化及诛杀','巧言谄媚，阿谀逢迎，惯于迎合上意','隋朝',1,'2026-04-10 11:18:00.635140','2026-04-10 11:18:00.635140','/images/ancient_character_men.webp'),(569,'杨玄感','男','?',613,'弘农华阴','隋朝权臣杨素长子，承袭楚国公爵位，官至礼部尚书，因隋炀帝对杨氏家族心存猜忌，趁隋王朝二征高句丽之际起兵反隋','骁勇倜傥，喜好结交天下名士，性格骄矜，用兵优柔寡断','隋朝',1,'2026-04-10 11:20:24.631107','2026-04-10 11:20:24.631107','/images/ancient_character_men.webp'),(570,'李密','男',582,619,'辽东襄平（今辽宁辽阳）','出身关陇贵族集团，是西魏八柱国之一李弼的曾孙，隋末瓦岗寨农民起义军领袖，早年参与杨玄感反隋，失败后投奔瓦岗寨，接替翟让统领瓦岗军，势力一度极盛，被王世充击败后降唐，不久后因叛唐被唐军击杀','志向远大但格局狭隘，多谋寡断，刚愎自矜，不能容人','隋朝',1,'2026-04-10 11:22:33.580512','2026-04-10 11:22:33.580512','/images/ancient_character_men.webp'),(571,'裴仁基','男','?',619,'河东闻喜（今山西省运城市闻喜县）','出身名门河东裴氏，隋末将领，早年出仕北周，隋朝建立后参与攻灭陈朝，多次出征边地，隋末奉命镇压农民起义，因受朝廷监官排挤逼迫，投降瓦岗寨李密，李密败于王世充后裴仁基被俘，获王世充任用，后预谋诛杀王世充归降唐朝，事泄被杀','骁勇善战，性格宽厚','隋朝',1,'2026-04-10 11:24:58.225394','2026-04-10 11:24:58.225394','/images/ancient_character_men.webp'),(572,'刘弘','未知',0,NULL,'未知','未知','未知','未知',1,'2026-04-10 11:27:25.304529','2026-04-10 11:27:25.304529','/images/ancient_character_men.webp'),(573,'皇甫诞','男','?',604,'安定乌氏（今甘肃省平凉市）','出身安定皇甫氏，南北朝至隋朝官员，北周时期入仕，隋朝建立后历任比部侍郎、刑部侍郎、尚书右丞、并州总管司马，隋炀帝即位后汉王杨谅起兵反叛，皇甫诞拒绝参与叛乱，被叛军杀害','忠正刚直，守节不屈','隋朝',1,'2026-04-10 11:29:21.828104','2026-04-10 11:29:21.828104','/images/ancient_character_men.webp'),(574,'陶模','男',1835,1902,'浙江秀水（今浙江嘉兴）','晚清重臣，同治七年进士，历任知县、知州、按察使、陕西布政使，后升任陕西巡抚、两广总督，任内整顿吏治、兴办新学、抵御列强侵略，主张开发西北边疆，是清末支持维新变革的代表性官员之一','清廉刚正，务实爱民，不阿权贵','清朝',1,'2026-04-10 11:30:33.367085','2026-04-10 11:30:33.367085','/images/ancient_character_men.webp'),(575,'敬钊','暂无明确记载','?','?','暂无明确记载','暂无可考的明确公开历史记载，不属于广为流传的知名历史人物','暂无明确记载','暂无明确记载',1,'2026-04-10 11:31:53.647582','2026-04-10 11:31:53.647582','/images/ancient_character_men.webp'),(576,'游元','男','?',618,'广平任（今河北省邢台市任泽区）','出身北魏官宦世家，为北魏名臣游明根玄孙，历仕北齐、北周、隋朝，隋代官至治书侍御史，隋大业十四年江都之变时，因拒绝依附弑君的宇文化及而被害','刚直不阿，素有胆气','隋朝',1,'2026-04-10 11:33:16.621914','2026-04-10 11:33:16.621914','/images/ancient_character_men.webp'),(577,'冯慈明','男',535,617,'长乐信都（今河北省衡水市冀州区）','出身门阀长乐冯氏，是北齐吏部尚书冯子琮之子，先后历仕北齐、北周，隋朝建立后历任尚书兵曹郎、开府仪同三司、银青光禄大夫；隋炀帝大业年间奉命赴东都洛阳，途中被李密起义军俘获，坚守隋臣气节拒绝招降，最终被李密杀害。','忠刚正直，守节不屈','隋朝',1,'2026-04-10 11:34:30.856235','2026-04-10 11:34:30.856235','/images/ancient_character_men.webp'),(578,'张须陀','男','?',616,'弘农阌乡（今河南灵宝）','隋朝名将，出身弘农张氏，早年追随越国公杨素平定汉王杨谅叛乱，隋末农民起义爆发后，作为隋军主力统帅长期在中原镇压各路起义军，是隋朝后期朝廷倚重的核心军事将领，最终在大海寺之战中被瓦岗军击杀','骁勇刚烈，忠君善战，勇猛果决','隋朝',1,'2026-04-10 11:36:43.542751','2026-04-10 11:36:43.542751','/images/ancient_character_men.webp'),(579,'杨善会','男','?','?','弘农华阴（今陕西华阴）','出身弘农杨氏，为隋朝官员，历任繁畤县令、清河郡丞，后升任清河太守，任职期间长期率兵镇压隋末农民起义，最终被窦建德起义军击败俘获，拒降被杀。','忠勇刚烈，骁勇有谋','隋朝',1,'2026-04-10 11:38:22.910108','2026-04-10 11:38:22.910108','/images/ancient_character_men.webp'),(580,'独孤盛','男','?',618,'上谷（今河北省怀来县一带）','隋朝将领，隋炀帝在位时官至右屯卫将军，大业十四年宇文化及发动江都之变谋弑隋炀帝，独孤盛率部对抗叛军，兵败身死','忠勇刚毅，忠君守节，宁死不屈','隋朝',1,'2026-04-10 11:39:24.989364','2026-04-10 11:39:24.989364','/images/ancient_character_men.webp'),(581,'元文都','男','?',618,'河南洛阳','北魏景穆帝拓跋晃后裔，北周时期入仕，隋朝建立后历任尚书左丞、太府卿等职，隋炀帝遇弑后，与段达、王世充等在洛阳拥立越王杨侗为帝，官拜内史令，后谋划诛杀王世充事泄被杀','耿直忠烈，明辩有器干','隋朝',1,'2026-04-10 11:40:31.155639','2026-04-10 11:40:31.155639','/images/ancient_character_men.webp'),(582,'卢楚','男','?',618,'涿郡范阳','出身范阳卢氏，为隋朝大臣，隋炀帝被弑后，与元文都等人拥立越王杨侗为帝，官至内史令，后因谋划诛杀王世充事泄被杀','刚直严厉，鲠直不阿','隋朝',1,'2026-04-10 11:42:22.318985','2026-04-10 11:42:22.318985','/images/ancient_character_men.webp'),(583,'刘子翊','男','?','?','彭城丛亭里（今江苏徐州）','出身彭城刘氏，早年历仕北齐、北周，隋建立后入仕，以吏治能力升任官职，最终官至襄城太守，隋末战乱时率军对抗乱兵，战败战死','好学博闻，刚正不阿，为官清廉，不附权贵','隋朝',1,'2026-04-10 11:44:00.711436','2026-04-10 11:44:00.711436','/images/ancient_character_men.webp'),(584,'尧君素','男','?',618,'魏郡汤阴（今河南省安阳市汤阴县）','隋朝末年将领，早年侍奉晋王杨广，杨广即位后累迁鹰击郎将，隋末天下大乱，尧君素奉命镇守河东，坚持对抗李唐势力，多次拒绝招降','忠勇刚烈，忠贞不屈','隋朝',1,'2026-04-10 11:45:20.985344','2026-04-10 11:45:20.985344','/images/ancient_character_men.webp'),(585,'陈孝意','男','?',617,'河东绛郡（今山西新绛）','隋朝诚节名臣，早年曾任鲁郡司法书佐，因断案公允闻名，后迁侍御史，隋炀帝时期出任雁门郡丞，刘武周起兵反隋时，他拒绝招降、坚守雁门郡城，最终被叛军杀害','生性耿直，公正清廉，忠君守节','隋朝',1,'2026-04-10 11:47:06.251528','2026-04-10 11:47:06.251528','/images/ancient_character_men.webp'),(586,'张季珣','男','?',617,'京兆万年','出身将门，父亲张祥为隋朝并州司马，早年凭借父荫入仕，隋末官至汲郡太守，隋末天下大乱时拒绝李密招降，坚持坚守城池，城破后被俘遇害','忠烈刚直，守节不屈','隋朝',1,'2026-04-10 11:48:37.541590','2026-04-10 11:48:37.541590','/images/ancient_character_men.webp'),(587,'松赟','男','?',613,'北海郡（今山东省潍坊市境内）','隋代隐士，以孝行闻名乡里，隋大业初年被举荐为孝廉，未出仕。大业九年杨玄感叛乱时，被叛军逼迫任职，宁死不从，投水殉节','狷介刚直，重孝守节，宁死不屈','隋朝',1,'2026-04-10 11:49:56.527931','2026-04-10 11:49:56.527931','/images/ancient_character_men.webp'),(588,'陆彦师','男',531,582,'吴郡吴县（今江苏省苏州市），后寓居河间','出身官宦世家，为北魏吏部尚书陆希道之子。自幼好学有品行，弱冠之年被州府征召为主簿，先后出仕北魏、东魏、北齐、北周、隋五个朝代。北齐时待诏文林馆，参与修撰类书《御览》，后迁通直散骑常侍并出使南陈；入北周后历任纳言上士、内史下大夫；隋朝开皇初年拜秘书丞，后转任尚书左丞，最终卒于任上。','沉静稳重，博学多才，擅长撰文，为官勤勉干练、谨严持重，以才干闻名于当时。','南北朝至隋朝',1,'2026-04-10 15:40:05.663695','2026-04-10 15:40:05.663695','/images/ancient_character_men.webp'),(589,'田德懋','男','?','?','京兆长安（今陕西西安）','隋朝观国公田仁恭之子，年少便以孝友之名著称，父亲田仁恭去世后辞官赴丧，哀毁过礼获朝廷旌表，后袭爵观国公，历任太子舍人、郓州刺史等职，任内为政宽厚，深得百姓爱戴，其事迹载入《隋书·孝义传》','孝谨纯厚，仁厚爱民，居丧尽礼，为官清正体恤民情','隋朝',1,'2026-04-10 15:40:43.658572','2026-04-10 15:40:43.658572','/images/ancient_character_men.webp'),(590,'薛濬','男','?','?','河东汾阴（今山西省万荣县西南）','出身官宦世家，父亲为北周尚书左丞薛端。早年好学，初仕北周，隋朝建立后历任尚书虞部侍郎、太府少卿等职，曾奉命出使突厥，参与修定五礼，为官颇有才干与政绩，后卒于任上','聪慧明敏，有器干，善于调和朝中争议，深受当时人称道；居家以孝行闻名，抚养亡兄之子胜过自己的子女，为世人所敬重','隋朝',1,'2026-04-10 15:42:17.198176','2026-04-10 15:42:17.198176','/images/ancient_character_men.webp'),(592,'王颁','男','?',593,'太原祁县（今山西省晋中市祁县）','南朝梁太尉王僧辩次子，侯景之乱时随父驰援建康，父亲王僧辩被陈霸先袭杀后，王颁辗转投奔北齐，后又入北周。隋朝建立后出仕，开皇八年随军参与隋灭陈之战，灭陈后他私自挖掘陈霸先的陵墓，鞭尸焚骨以报父仇，此后历任官职，最终于开皇十三年去世。','刚毅果敢，重孝义，隐忍有谋，行事果决','隋朝',1,'2026-04-10 15:44:18.285911','2026-04-10 15:44:18.285911','/images/ancient_character_men.webp'),(594,'杨庆','男','?',621,'河间（今河北河间）','隋朝宗室，河间王杨弘之子。早年在隋朝任职，隋末天下大乱之际先后依附李密、王世充，王世充称帝后受封郇王，武德四年随王世充降唐','为人巧佞善辩，缺乏坚定节操，反复无常，为自保多次改换阵营','隋末唐初',1,'2026-04-10 15:46:33.891292','2026-04-10 15:46:33.891292','/images/ancient_character_men.webp');
