DROP TABLE IF EXISTS `character_event`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `character_event` (
  `id` int NOT NULL AUTO_INCREMENT,
  `characterId` int NOT NULL,
  `year` varchar(255) NOT NULL,
  `age` varchar(255) NOT NULL,
  `title` varchar(255) NOT NULL,
  `description` varchar(255) NOT NULL,
  `impact` varchar(255) NOT NULL,
  `order` int NOT NULL DEFAULT '0',
  `createdAt` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updatedAt` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  PRIMARY KEY (`id`),
  KEY `FK_49d576c5792a5695f0e30990724` (`characterId`),
  CONSTRAINT `FK_49d576c5792a5695f0e30990724` FOREIGN KEY (`characterId`) REFERENCES `character` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1338 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
